{
  "name": "Nano Banana 批量反推库",
  "description": "基于 Gemini API 的 AI 绘画提示词批量反推灵感库，支持图片上传、自动分析与多维筛选管理。"
}

export type Category = '人物' | '风景' | '产品' | '家居' | '动漫' | '建筑' | '其他';

export interface PromptEntry {
  id: string;
  thumbnail: string;
  summary: string;
  category: Category;
  tags: string[];
  fullPrompt: string;
  createdAt: number;
}

export interface AnalysisResult {
  summary: string;
  category: Category;
  tags: string[];
  fullPrompt: string;
}

export interface ProcessingState {
  total: number;
  current: number;
  isProcessing: boolean;
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) throw new Error("Could not find root element");

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "./types";

const ANALYSIS_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    summary: { type: Type.STRING, description: "15字以内的画面概括" },
    category: { type: Type.STRING, enum: ['人物', '风景', '产品', '家居', '动漫', '建筑', '其他'] },
    tags: { type: Type.ARRAY, items: { type: Type.STRING }, description: "5-8个核心标签" },
    fullPrompt: { type: Type.STRING, description: "详细中文描述，包括构图、风格、光影等要素" },
  },
  required: ["summary", "category", "tags", "fullPrompt"],
};

export const analyzeImage = async (base64Image: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: 'image/jpeg', data: base64Image.split(',')[1] } },
        { text: "请分析这张图片，按照给定的JSON格式输出：简述、分类、关键词、完整提示词。要求描述详尽且精准，适用于AI绘画参考。" }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: ANALYSIS_SCHEMA
    }
  });

  return JSON.parse(response.text || '{}') as AnalysisResult;
};

export const compressImage = (file: File): Promise<string> => {
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = (event) => {
      const img = new Image();
      img.src = event.target?.result as string;
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        const scale = 200 / img.width;
        canvas.width = 200;
        canvas.height = img.height * scale;
        ctx?.drawImage(img, 0, 0, canvas.width, canvas.height);
        resolve(canvas.toDataURL('image/jpeg', 0.8));
      };
    };
  });
};

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { PromptEntry, ProcessingState, Category } from './types';
