              <Upload className="w-8 h-8 text-slate-400" />
            </div>
            <p className="mb-2 text-sm text-slate-300"><span className="font-semibold text-yellow-400">点击上传</span> 或 拖拽图片到此处</p>
            <p className="text-xs text-slate-500">支持批量处理（建议一次最多 20 张）</p>
          </div>
          <input type="file" className="hidden" multiple accept="image/*" onChange={(e) => e.target.files && processFiles(e.target.files)} disabled={proc.isProcessing} />
        </label>
      </section>

      {/* Library Section */}
