export type Category = '人物' | '风景' | '产品' | '家居' | '动漫' | '建筑' | '其他';

export interface PromptEntry {
  id: string;
  thumbnail: string;
  summary: string;
  category: Category;
  tags: string[];
  fullPrompt: string;
  cameraInfo?: string;
  materialDescription?: string; // 新增：材质与纹理描述
  createdAt: number;
}

export interface AnalysisResult {
  summary: string;
  category: Category;
  tags: string[];
  fullPrompt: string;
  cameraInfo: string;
