import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { PromptEntry, ProcessingState, Category } from './types';
import { analyzeImage, compressImage } from './geminiService';
import { Search, Upload, Copy, Trash2, Printer, Loader2, Filter, X, Check, Edit2, Camera, Layers, ChevronDown, Maximize2, Code, FileJson } from 'lucide-react';

const CATEGORIES: Category[] = ['人物', '风景', '产品', '家居', '动漫', '建筑', '其他'];

const App: React.FC = () => {
  const [entries, setEntries] = useState<PromptEntry[]>([]);
  const [proc, setProc] = useState<ProcessingState>({ total: 0, current: 0, isProcessing: false });
  const [search, setSearch] = useState('');
  const [catFilter, setCatFilter] = useState<Category | '全部'>('全部');
  const [isDragging, setIsDragging] = useState(false);

  // 预览状态
  const [previewEntry, setPreviewEntry] = useState<PromptEntry | null>(null);

  // 行内编辑状态
  const [editingId, setEditingId] = useState<string | null>(null);
  const [tempPrompt, setTempPrompt] = useState('');

  // 持久化
  useEffect(() => {
    const saved = localStorage.getItem('nano_banana_db');
    if (saved) setEntries(JSON.parse(saved));
  }, []);

  useEffect(() => {
    localStorage.setItem('nano_banana_db', JSON.stringify(entries));
  }, [entries]);

  const processFiles = async (files: FileList) => {
    if (proc.isProcessing) return;
    const fileArray = Array.from(files).slice(0, 20);
    setProc({ total: fileArray.length, current: 0, isProcessing: true });

    for (let i = 0; i < fileArray.length; i++) {
      try {
        setProc(prev => ({ ...prev, current: i + 1 }));
        const thumb = await compressImage(fileArray[i]);

        const reader = new FileReader();
        const base64: string = await new Promise((resolve) => {
          reader.onload = (e) => resolve(e.target?.result as string);
          reader.readAsDataURL(fileArray[i]);
        });

        const result = await analyzeImage(base64);

        const newEntry: PromptEntry = {
          id: Date.now().toString() + Math.random().toString(36).substr(2, 9),
          thumbnail: thumb,
          ...result,
          createdAt: Date.now()
        };

        setEntries(prev => [newEntry, ...prev]);
      } catch (error) {
        console.error('Failed to process image:', error);
      }
    }
    setProc({ total: 0, current: 0, isProcessing: false });
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    alert('已复制到剪贴板');
  };

  const handleDelete = (id: string) => {
    if (confirm('确认删除此灵感？')) {
      setEntries(prev => prev.filter(e => e.id !== id));
    }
  };

  const startEditing = (entry: PromptEntry) => {
    setEditingId(entry.id);
    setTempPrompt(entry.fullPrompt);
  };

  const saveEdit = (id: string) => {
    setEntries(prev => prev.map(e => e.id === id ? { ...e, fullPrompt: tempPrompt } : e));
    setEditingId(null);
  };

  const cancelEdit = () => {
    setEditingId(null);
    setTempPrompt('');
  };

  const filteredEntries = useMemo(() => {
    return entries.filter(e => {
      const matchesSearch = 
        e.summary.includes(search) || 
        e.fullPrompt.includes(search) || 
        (e.cameraInfo?.includes(search)) ||
        (e.materialDescription?.includes(search)) ||
        e.tags.some(t => t.includes(search));
      const matchesCat = catFilter === '全部' || e.category === catFilter;
      return matchesSearch && matchesCat;
    });
  }, [entries, search, catFilter]);

  const handleExport = () => window.print();

  const getCategoryColor = (cat: Category) => {
    const map: Record<Category, string> = {
      '人物': 'bg-pink-500/20 text-pink-400 border-pink-500/30',
      '风景': 'bg-green-500/20 text-green-400 border-green-500/30',
      '产品': 'bg-blue-500/20 text-blue-400 border-blue-500/30',
      '家居': 'bg-orange-500/20 text-orange-400 border-orange-500/30',
      '动漫': 'bg-purple-500/20 text-purple-400 border-purple-500/30',
      '建筑': 'bg-yellow-500/20 text-yellow-400 border-yellow-500/30',
      '其他': 'bg-slate-500/20 text-slate-400 border-slate-500/30',
    };
    return map[cat];
  };

  const formatJSON = (entry: PromptEntry) => {
    const { id, thumbnail, createdAt, ...rest } = entry;
    return JSON.stringify(rest, null, 2);
  };

  return (
    <div className="max-w-7xl mx-auto p-6 md:p-10 space-y-8 min-h-screen font-sans">
      {/* Header */}
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-6 bg-white/5 backdrop-blur-lg p-6 rounded-3xl border border-white/10 no-print shadow-xl">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-gradient-to-br from-yellow-400 to-orange-600 rounded-xl flex items-center justify-center shadow-lg shadow-orange-500/20">
            <span className="text-2xl">🍌</span>
          </div>
          <div>
            <h1 className="text-2xl font-bold tracking-tight">Nano Banana 批量反推库</h1>
            <p className="text-slate-400 text-sm">AI 视觉驱动的摄影、材质与绘画灵感管理</p>
          </div>
        </div>

        {proc.isProcessing && (
          <div className="flex items-center gap-4 bg-slate-900/50 px-4 py-2 rounded-2xl border border-white/5">
            <Loader2 className="w-5 h-5 text-yellow-400 animate-spin" />
            <div className="flex flex-col">
              <span className="text-xs text-slate-400">正在处理 {proc.current}/{proc.total}</span>
              <div className="w-32 h-1.5 bg-slate-700 rounded-full mt-1 overflow-hidden">
                <div 
                  className="h-full bg-yellow-400 transition-all duration-300" 
                  style={{ width: `${(proc.current / proc.total) * 100}%` }}
                />
              </div>
            </div>
          </div>
        )}
      </header>

      {/* Upload Zone */}
      <section 
        className={`no-print relative group transition-all duration-300 ${isDragging ? 'scale-[1.01]' : ''}`}
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={(e) => { e.preventDefault(); setIsDragging(false); processFiles(e.dataTransfer.files); }}
      >
        <label className={`flex flex-col items-center justify-center w-full h-48 border-2 border-dashed rounded-3xl cursor-pointer transition-colors ${isDragging ? 'border-yellow-400 bg-yellow-400/5' : 'border-white/10 hover:border-white/20 hover:bg-white/5'}`}>
