                          className="text-xs text-slate-400 max-w-xs truncate cursor-text hover:text-yellow-400 group-hover:whitespace-normal group-hover:bg-slate-900 group-hover:p-4 group-hover:absolute group-hover:z-[60] group-hover:shadow-2xl group-hover:rounded-2xl group-hover:border group-hover:border-white/10 group-hover:top-0 group-hover:left-0 group-hover:w-80 transition-all flex items-center gap-2"
                        >
                          {entry.fullPrompt}
                          <Edit2 className="w-3 h-3 opacity-0 group-hover:opacity-100 flex-shrink-0" />
                        </div>
                      )}
                    </td>
                    <td className="px-6 py-4 no-print">
                      <div className="flex items-center gap-2">
                        <button 
                          onClick={() => handleCopy(entry.fullPrompt)}
                          className="p-2 hover:bg-white/10 rounded-lg text-slate-400 hover:text-yellow-400 transition-colors"
                          title="复制提示词"
                        >
                          <Copy className="w-4 h-4" />
                        </button>
                        <button 
                          onClick={() => handleCopy(formatJSON(entry))}
                          className="p-2 hover:bg-white/10 rounded-lg text-slate-400 hover:text-blue-400 transition-colors"
                          title="复制 JSON 数据"
                        >
                          <FileJson className="w-4 h-4" />
                        </button>
                        <button 
                          onClick={() => handleDelete(entry.id)}
                          className="p-2 hover:bg-red-500/10 rounded-lg text-slate-400 hover:text-red-400 transition-colors"
                          title="删除"
                        >
                          <Trash2 className="w-4 h-4" />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            {filteredEntries.length === 0 && (
              <div className="flex flex-col items-center justify-center py-20 text-slate-500">
                <Search className="w-12 h-12 mb-4 opacity-20" />
                <p>暂无灵感数据，请上传图片开始分析</p>
              </div>
            )}
          </div>
        </div>
      </main>

      {/* Lighbox Modal */}
      {previewEntry && (
        <div 
          className="fixed inset-0 z-[100] flex items-center justify-center p-4 md:p-8 no-print animate-in fade-in duration-200"
          onClick={() => setPreviewEntry(null)}
        >
          <div className="absolute inset-0 bg-slate-950/90 backdrop-blur-xl" />

          <div 
            className="relative max-w-6xl w-full max-h-[90vh] flex flex-col md:flex-row gap-6 bg-slate-900 border border-white/10 rounded-[2.5rem] p-4 md:p-6 shadow-2xl animate-in zoom-in-95 duration-300 overflow-hidden"
            onClick={(e) => e.stopPropagation()}
          >
            <button 
              onClick={() => setPreviewEntry(null)}
              className="absolute top-4 right-4 z-20 p-2 bg-white/5 hover:bg-white/10 rounded-full text-slate-400 transition-colors"
            >
              <X className="w-6 h-6" />
            </button>

            {/* Large Image */}
            <div className="flex-[1.5] min-h-0 flex items-center justify-center bg-black/20 rounded-3xl overflow-hidden p-2">
              <img 
                src={previewEntry.thumbnail} 
                alt="preview" 
                className="max-w-full max-h-full object-contain rounded-2xl"
              />
            </div>

            {/* Info Sidebar */}
            <div className="flex-1 min-w-0 flex flex-col gap-5 overflow-y-auto pr-2 custom-scrollbar">
              <div className="flex items-center gap-3">
                <span className={`px-2.5 py-1 rounded-full text-[10px] font-bold border ${getCategoryColor(previewEntry.category)}`}>
                  {previewEntry.category}
                </span>
                <h2 className="text-xl font-bold text-slate-100 truncate">{previewEntry.summary}</h2>
              </div>

              <div className="grid grid-cols-2 gap-3 py-2 border-y border-white/5">
                <div className="space-y-1">
                  <span className="text-[9px] uppercase tracking-wider text-slate-500 font-bold">摄影参数</span>
                  <div className="flex items-center gap-2 text-xs text-yellow-400/90 bg-yellow-400/5 p-2 rounded-xl border border-yellow-400/10">
                    <Camera className="w-3.5 h-3.5 flex-shrink-0" />
                    <span className="truncate" title={previewEntry.cameraInfo}>{previewEntry.cameraInfo || '无数据'}</span>
                  </div>
                </div>

                <div className="space-y-1">
                  <span className="text-[9px] uppercase tracking-wider text-slate-500 font-bold">核心材质</span>
                  <div className="flex items-center gap-2 text-xs text-blue-400/90 bg-blue-400/5 p-2 rounded-xl border border-blue-400/10">
                    <Layers className="w-3.5 h-3.5 flex-shrink-0" />
                    <span className="truncate" title={previewEntry.materialDescription}>{previewEntry.materialDescription || '无数据'}</span>
                  </div>
                </div>
              </div>

              {/* Prompt Block */}
              <div className="space-y-2">
                <div className="flex items-center justify-between">
                  <span className="text-[9px] uppercase tracking-wider text-slate-500 font-bold">完整反推提示词</span>
                  <button onClick={() => handleCopy(previewEntry.fullPrompt)} className="text-[9px] text-yellow-400 hover:underline">点击复制</button>
                </div>
                <div className="bg-white/5 p-4 rounded-2xl text-xs text-slate-300 leading-relaxed border border-white/5 italic">
                  "{previewEntry.fullPrompt}"
                </div>
              </div>

              {/* JSON Block */}
              <div className="space-y-2 mt-auto">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-1.5 text-slate-500">
                    <FileJson className="w-3 h-3" />
                    <span className="text-[9px] uppercase tracking-wider font-bold">JSON 结构化数据</span>
                  </div>
                  <button onClick={() => handleCopy(formatJSON(previewEntry))} className="text-[9px] text-blue-400 hover:underline">复制 JSON</button>
                </div>
                <div className="bg-black/40 p-4 rounded-2xl font-mono text-[10px] text-slate-400 border border-white/5 max-h-40 overflow-y-auto">
                  <pre className="whitespace-pre-wrap">
                    {formatJSON(previewEntry).split('\n').map((line, i) => {
                      const match = line.match(/"(\w+)":/);
                      if (match) {
                        return (
                          <span key={i}>
                            <span className="text-blue-400/80">"{match[1]}"</span>:
                            <span className="text-orange-400/80">{line.split(match[0])[1]}</span>
                            {'\n'}
                          </span>
                        );
                      }
                      return line + '\n';
                    })}
                  </pre>
                </div>
              </div>

              <div className="flex gap-3">
                <button 
                  onClick={() => handleCopy(previewEntry.fullPrompt)}
                  className="flex-1 py-3 bg-yellow-400 hover:bg-yellow-500 text-slate-950 rounded-2xl font-bold transition-all flex items-center justify-center gap-2 shadow-lg shadow-yellow-400/20 active:scale-95"
                >
                  <Copy className="w-4 h-4" /> 复制提示词
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Print View Wrapper */}
      <div className="print-only">
        <h1 className="text-3xl font-bold mb-6 text-black">Nano Banana 灵感库导出</h1>
        <div className="space-y-8">
          {filteredEntries.map((entry, idx) => (
            <div key={entry.id} className="card p-6 border-b border-gray-200 break-inside-avoid">
              <div className="flex gap-6">
                <img src={entry.thumbnail} className="w-32 h-32 object-cover rounded-lg" />
                <div className="space-y-2">
                  <div className="flex items-center gap-3">
                    <span className="text-xl font-bold">#{idx + 1} {entry.summary}</span>
                    <span className="text-sm border border-black px-2 py-0.5 rounded uppercase">{entry.category}</span>
                  </div>
                  <p className="text-sm text-gray-800"><strong>技术参数:</strong> {entry.cameraInfo}</p>
                  <p className="text-sm text-blue-800"><strong>材质描述:</strong> {entry.materialDescription}</p>
                  <p className="text-sm text-gray-600"><strong>标签:</strong> {entry.tags.join(', ')}</p>
                  <p className="text-sm leading-relaxed"><strong>完整提示词:</strong> {entry.fullPrompt}</p>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { PromptEntry, ProcessingState, Category } from './types';
import { analyzeImage, compressImage } from './geminiService';
import { Search, Upload, Copy, Trash2, Printer, Loader2, Filter, X, Check, Edit2, Camera, Layers, Maximize2, FileJson, Hash } from 'lucide-react';

const CATEGORIES: Category[] = ['人物', '风景', '产品', '家居', '动漫', '建筑', '其他'];

const App: React.FC = () => {
  const [entries, setEntries] = useState<PromptEntry[]>([]);
  const [proc, setProc] = useState<ProcessingState>({ total: 0, current: 0, isProcessing: false });
  const [search, setSearch] = useState('');
  const [catFilter, setCatFilter] = useState<Category | '全部'>('全部');
  const [isDragging, setIsDragging] = useState(false);

  // 预览状态
  const [previewEntry, setPreviewEntry] = useState<PromptEntry | null>(null);

  // 行内编辑状态
  const [editingId, setEditingId] = useState<string | null>(null);
  const [tempPrompt, setTempPrompt] = useState('');

  // 持久化
  useEffect(() => {
    const saved = localStorage.getItem('nano_banana_db');
    if (saved) setEntries(JSON.parse(saved));
  }, []);

  useEffect(() => {
    localStorage.setItem('nano_banana_db', JSON.stringify(entries));
  }, [entries]);

  const processFiles = async (files: FileList) => {
    if (proc.isProcessing) return;
    const fileArray = Array.from(files).slice(0, 20);
    setProc({ total: fileArray.length, current: 0, isProcessing: true });

    for (let i = 0; i < fileArray.length; i++) {
      try {
        setProc(prev => ({ ...prev, current: i + 1 }));
        const thumb = await compressImage(fileArray[i]);

        const reader = new FileReader();
        const base64: string = await new Promise((resolve) => {
          reader.onload = (e) => resolve(e.target?.result as string);
          reader.readAsDataURL(fileArray[i]);
        });

        const result = await analyzeImage(base64);

        const newEntry: PromptEntry = {
          id: Date.now().toString() + Math.random().toString(36).substr(2, 9),
          thumbnail: thumb,
          ...result,
          createdAt: Date.now()
        };

        setEntries(prev => [newEntry, ...prev]);
      } catch (error) {
        console.error('Failed to process image:', error);
      }
    }
    setProc({ total: 0, current: 0, isProcessing: false });
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    alert('已复制到剪贴板');
  };

  const handleDelete = (id: string) => {
    if (confirm('确认删除此灵感？')) {
      setEntries(prev => prev.filter(e => e.id !== id));
    }
  };

  const startEditing = (entry: PromptEntry) => {
    setEditingId(entry.id);
    setTempPrompt(entry.fullPrompt);
  };

  const saveEdit = (id: string) => {
    setEntries(prev => prev.map(e => e.id === id ? { ...e, fullPrompt: tempPrompt } : e));
    setEditingId(null);
  };

  const cancelEdit = () => {
    setEditingId(null);
    setTempPrompt('');
  };

  const filteredEntries = useMemo(() => {
    return entries.filter(e => {
      const matchesSearch = 
        e.summary.includes(search) || 
        e.fullPrompt.includes(search) || 
        (e.cameraInfo?.includes(search)) ||
        (e.materialDescription?.includes(search)) ||
        e.tags.some(t => t.includes(search));
      const matchesCat = catFilter === '全部' || e.category === catFilter;
      return matchesSearch && matchesCat;
    });
  }, [entries, search, catFilter]);

  const handleExport = () => window.print();

  const getCategoryColor = (cat: Category) => {
    const map: Record<Category, string> = {
      '人物': 'bg-pink-500/20 text-pink-400 border-pink-500/30',
      '风景': 'bg-green-500/20 text-green-400 border-green-500/30',
      '产品': 'bg-blue-500/20 text-blue-400 border-blue-500/30',
      '家居': 'bg-orange-500/20 text-orange-400 border-orange-500/30',
      '动漫': 'bg-purple-500/20 text-purple-400 border-purple-500/30',
      '建筑': 'bg-yellow-500/20 text-yellow-400 border-yellow-500/30',
      '其他': 'bg-slate-500/20 text-slate-400 border-slate-500/30',
    };
    return map[cat];
  };

  const formatJSON = (entry: PromptEntry) => {
    const { id, thumbnail, createdAt, ...rest } = entry;
    return JSON.stringify(rest, null, 2);
  };

  return (
    <div className="max-w-7xl mx-auto p-6 md:p-10 space-y-8 min-h-screen font-sans">
      {/* Header */}
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-6 bg-white/5 backdrop-blur-lg p-6 rounded-3xl border border-white/10 no-print shadow-xl">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-gradient-to-br from-yellow-400 to-orange-600 rounded-xl flex items-center justify-center shadow-lg shadow-orange-500/20">
            <span className="text-2xl">🍌</span>
          </div>
          <div>
            <h1 className="text-2xl font-bold tracking-tight">Nano Banana 批量反推库</h1>
            <p className="text-slate-400 text-sm">AI 视觉驱动的摄影、材质与绘画灵感管理</p>
          </div>
        </div>

        {proc.isProcessing && (
          <div className="flex items-center gap-4 bg-slate-900/50 px-4 py-2 rounded-2xl border border-white/5">
            <Loader2 className="w-5 h-5 text-yellow-400 animate-spin" />
            <div className="flex flex-col">
              <span className="text-xs text-slate-400">正在处理 {proc.current}/{proc.total}</span>
              <div className="w-32 h-1.5 bg-slate-700 rounded-full mt-1 overflow-hidden">
                <div 
                  className="h-full bg-yellow-400 transition-all duration-300" 
                  style={{ width: `${(proc.current / proc.total) * 100}%` }}
                />
              </div>
            </div>
          </div>
        )}
      </header>

      {/* Upload Zone */}
      <section 
        className={`no-print relative group transition-all duration-300 ${isDragging ? 'scale-[1.01]' : ''}`}
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={(e) => { e.preventDefault(); setIsDragging(false); processFiles(e.dataTransfer.files); }}
      >
        <label className={`flex flex-col items-center justify-center w-full h-48 border-2 border-dashed rounded-3xl cursor-pointer transition-colors ${isDragging ? 'border-yellow-400 bg-yellow-400/5' : 'border-white/10 hover:border-white/20 hover:bg-white/5'}`}>
          <div className="flex flex-col items-center justify-center pt-5 pb-6">
            <div className="p-3 bg-white/5 rounded-2xl mb-3 group-hover:scale-110 transition-transform">
              <Upload className="w-8 h-8 text-slate-400" />
            </div>
            <p className="mb-2 text-sm text-slate-300"><span className="font-semibold text-yellow-400">点击上传</span> 或 拖拽图片到此处</p>
            <p className="text-xs text-slate-500">支持批量处理（建议一次最多 20 张）</p>
          </div>
          <input type="file" className="hidden" multiple accept="image/*" onChange={(e) => e.target.files && processFiles(e.target.files)} disabled={proc.isProcessing} />
        </label>
      </section>

      {/* Library Section */}
      <main className="space-y-6">
        <div className="flex flex-col space-y-4 no-print">
          {/* Toolbar Top: Search & Export */}
          <div className="flex flex-wrap items-center justify-between gap-4">
            <div className="relative flex-1 max-w-md">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
              <input 
                type="text" 
                placeholder="搜索简述、相机、材质参数..." 
                className="w-full pl-10 pr-4 py-3 bg-slate-900 border border-white/10 rounded-2xl focus:outline-none focus:ring-2 focus:ring-yellow-400/50 text-sm text-slate-100 shadow-inner transition-all"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
              />
            </div>
            <button 
              onClick={handleExport}
              className="flex items-center gap-2 px-6 py-3 bg-white/5 hover:bg-white/10 border border-white/10 rounded-2xl text-sm transition-all text-slate-300 hover:text-white"
            >
              <Printer className="w-4 h-4" /> 导出灵感库
            </button>
          </div>

          {/* Toolbar Bottom: Category Pills */}
          <div className="flex items-center gap-3 overflow-x-auto pb-2 custom-scrollbar no-print">
            <div className="flex items-center gap-2 pr-4 border-r border-white/10 mr-2 shrink-0">
              <Filter className="w-4 h-4 text-slate-500" />
              <span className="text-xs font-bold text-slate-500 uppercase tracking-widest">分类筛选</span>
            </div>
            <div className="flex gap-2 flex-nowrap">
              <button
                onClick={() => setCatFilter('全部')}
                className={`px-4 py-2 rounded-xl text-xs font-medium transition-all border whitespace-nowrap ${
                  catFilter === '全部' 
                  ? 'bg-yellow-400/20 text-yellow-400 border-yellow-400/50 shadow-lg shadow-yellow-400/10' 
                  : 'bg-white/5 text-slate-400 border-white/10 hover:border-white/20 hover:text-slate-300'
                }`}
              >
                全部
              </button>
              {CATEGORIES.map(c => (
                <button
                  key={c}
                  onClick={() => setCatFilter(c)}
                  className={`px-4 py-2 rounded-xl text-xs font-medium transition-all border whitespace-nowrap ${
                    catFilter === c 
                    ? 'bg-yellow-400/20 text-yellow-400 border-yellow-400/50 shadow-lg shadow-yellow-400/10' 
                    : 'bg-white/5 text-slate-400 border-white/10 hover:border-white/20 hover:text-slate-300'
                  }`}
                >
                  {c}
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* Table View */}
        <div className="bg-white/5 backdrop-blur-xl border border-white/10 rounded-3xl overflow-hidden shadow-2xl">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-white/5 text-slate-400 text-[11px] font-bold uppercase tracking-wider">
                  <th className="px-6 py-5">序号</th>
                  <th className="px-6 py-5">预览</th>
                  <th className="px-6 py-5">类别</th>
                  <th className="px-6 py-5">简述</th>
                  <th className="px-6 py-5">技术与材质</th>
                  <th className="px-6 py-5">完整提示词</th>
                  <th className="px-6 py-5 no-print">操作</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/5">
                {filteredEntries.map((entry, idx) => (
                  <tr key={entry.id} className="group hover:bg-white/5 transition-colors">
                    <td className="px-6 py-4 text-sm text-slate-500 font-mono">{(idx + 1).toString().padStart(2, '0')}</td>
                    <td className="px-6 py-4">
                      <div 
                        className="relative group/img cursor-zoom-in overflow-hidden rounded-xl border border-white/10 shadow-sm"
                        onClick={() => setPreviewEntry(entry)}
                      >
                        <img 
                          src={entry.thumbnail} 
                          alt="thumb" 
                          className="w-16 h-16 object-cover transition-transform duration-500 group-hover/img:scale-110" 
                        />
                        <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover/img:opacity-100 transition-opacity">
                          <Maximize2 className="w-4 h-4 text-white" />
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`px-2.5 py-1 rounded-lg text-[10px] font-bold border ${getCategoryColor(entry.category)}`}>
                        {entry.category}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <p className="text-sm font-medium w-40 truncate leading-relaxed" title={entry.summary}>{entry.summary}</p>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex flex-col gap-2 max-w-[220px]">
                        <div className="flex items-center gap-2 text-[11px] text-yellow-400/80 bg-yellow-400/5 px-2 py-1 rounded-md border border-yellow-400/10">
                          <Camera className="w-3.5 h-3.5 flex-shrink-0" />
                          <span className="truncate" title={entry.cameraInfo}>{entry.cameraInfo || '未识别'}</span>
                        </div>
                        <div className="flex items-center gap-2 text-[11px] text-blue-400/80 bg-blue-400/5 px-2 py-1 rounded-md border border-blue-400/10">
                          <Layers className="w-3.5 h-3.5 flex-shrink-0" />
                          <span className="truncate" title={entry.materialDescription}>{entry.materialDescription || '未分析材质'}</span>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4 relative group min-w-[240px]">
                      {editingId === entry.id ? (
                        <div className="flex flex-col gap-2 z-50">
                          <textarea
                            className="w-full bg-slate-900 text-xs text-slate-200 p-3 rounded-xl border border-yellow-400/50 focus:outline-none focus:ring-2 focus:ring-yellow-400/50 min-h-[120px] resize-y shadow-2xl"
                            value={tempPrompt}
                            onChange={(e) => setTempPrompt(e.target.value)}
                            autoFocus
                          />
                          <div className="flex justify-end gap-2">
                            <button 
                              onClick={cancelEdit} 
                              className="p-1.5 bg-white/5 hover:bg-white/10 text-slate-400 rounded-lg transition-colors"
                            >
                              <X className="w-4 h-4" />
                            </button>
                            <button 
                              onClick={() => saveEdit(entry.id)} 
                              className="p-1.5 bg-yellow-400 text-slate-950 rounded-lg transition-colors hover:bg-yellow-500"
                            >
                              <Check className="w-4 h-4" />
                            </button>
                          </div>
                        </div>
                      ) : (
                        <div 
                          onClick={() => startEditing(entry)}
                          className="text-xs text-slate-400 max-w-xs truncate cursor-text hover:text-yellow-400 group-hover:whitespace-normal group-hover:bg-slate-900 group-hover:p-4 group-hover:absolute group-hover:z-[60] group-hover:shadow-2xl group-hover:rounded-2xl group-hover:border group-hover:border-white/10 group-hover:top-0 group-hover:left-0 group-hover:w-80 transition-all flex items-center gap-2"
                        >
                          <span className="italic">"{entry.fullPrompt}"</span>
                          <Edit2 className="w-3 h-3 opacity-0 group-hover:opacity-100 flex-shrink-0" />
                        </div>
                      )}
                    </td>
                    <td className="px-6 py-4 no-print">
                      <div className="flex items-center gap-1">
                        <button 
                          onClick={() => handleCopy(entry.fullPrompt)}
                          className="p-2.5 hover:bg-white/10 rounded-xl text-slate-400 hover:text-yellow-400 transition-colors"
                          title="复制提示词"
                        >
                          <Copy className="w-4 h-4" />
                        </button>
                        <button 
                          onClick={() => handleCopy(formatJSON(entry))}
                          className="p-2.5 hover:bg-white/10 rounded-xl text-slate-400 hover:text-blue-400 transition-colors"
                          title="复制 JSON"
                        >
                          <FileJson className="w-4 h-4" />
                        </button>
                        <button 
                          onClick={() => handleDelete(entry.id)}
                          className="p-2.5 hover:bg-red-500/10 rounded-xl text-slate-400 hover:text-red-400 transition-colors"
                          title="删除"
                        >
                          <Trash2 className="w-4 h-4" />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            {filteredEntries.length === 0 && (
              <div className="flex flex-col items-center justify-center py-24 text-slate-500">
                <div className="p-6 bg-white/5 rounded-full mb-4">
                  <Search className="w-12 h-12 opacity-20" />
                </div>
                <p className="text-sm font-medium">暂无灵感数据</p>
                <p className="text-xs opacity-50 mt-1">请尝试上传图片或更换搜索词</p>
              </div>
            )}
          </div>
        </div>
      </main>

      {/* Lightbox Modal */}
      {previewEntry && (
        <div 
          className="fixed inset-0 z-[100] flex items-center justify-center p-4 md:p-8 no-print animate-in fade-in duration-300"
          onClick={() => setPreviewEntry(null)}
        >
          <div className="absolute inset-0 bg-slate-950/95 backdrop-blur-xl" />

          <div 
            className="relative max-w-6xl w-full max-h-[90vh] flex flex-col md:flex-row gap-6 bg-slate-900 border border-white/10 rounded-[2.5rem] p-4 md:p-6 shadow-2xl animate-in zoom-in-95 duration-400 overflow-hidden"
            onClick={(e) => e.stopPropagation()}
          >
            <button 
              onClick={() => setPreviewEntry(null)}
              className="absolute top-6 right-6 z-20 p-2.5 bg-white/10 hover:bg-white/20 rounded-full text-white transition-all hover:rotate-90 shadow-xl"
            >
              <X className="w-6 h-6" />
            </button>

            {/* Large Image View */}
            <div className="flex-[1.8] min-h-0 flex items-center justify-center bg-black/40 rounded-[2rem] overflow-hidden p-2 group/zoom cursor-zoom-out" onClick={() => setPreviewEntry(null)}>
              <img 
                src={previewEntry.thumbnail} 
                alt="preview" 
                className="max-w-full max-h-full object-contain rounded-xl transition-transform duration-700 group-hover/zoom:scale-[1.02]"
              />
            </div>

            {/* Structured Info Sidebar */}
            <div className="flex-1 min-w-0 flex flex-col gap-6 overflow-y-auto pr-2 custom-scrollbar">
              <div>
                <div className="flex items-center gap-3 mb-2">
                  <span className={`px-3 py-1 rounded-full text-[10px] font-black tracking-widest border uppercase shadow-sm ${getCategoryColor(previewEntry.category)}`}>
                    {previewEntry.category}
                  </span>
                </div>
                <h2 className="text-2xl font-bold text-white tracking-tight leading-tight">{previewEntry.summary}</h2>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <span className="flex items-center gap-1.5 text-[10px] uppercase tracking-wider text-slate-500 font-black">
                    <Camera className="w-3 h-3" /> 摄影配置
                  </span>
                  <div className="bg-yellow-400/5 p-3 rounded-2xl border border-yellow-400/10 text-xs text-yellow-400 font-medium">
                    {previewEntry.cameraInfo || '无数据'}
                  </div>
                </div>
                <div className="space-y-1.5">
                  <span className="flex items-center gap-1.5 text-[10px] uppercase tracking-wider text-slate-500 font-black">
                    <Layers className="w-3 h-3" /> 核心材质
                  </span>
                  <div className="bg-blue-400/5 p-3 rounded-2xl border border-blue-400/10 text-xs text-blue-400 font-medium">
                    {previewEntry.materialDescription || '无数据'}
                  </div>
                </div>
              </div>

              <div className="space-y-2">
                <span className="flex items-center gap-1.5 text-[10px] uppercase tracking-wider text-slate-500 font-black">完整反推提示词</span>
                <div className="bg-white/5 p-5 rounded-2xl text-xs text-slate-200 leading-relaxed border border-white/5 shadow-inner italic">
                  "{previewEntry.fullPrompt}"
                </div>
              </div>

              <div className="space-y-2 mt-auto">
                <div className="flex items-center justify-between text-[10px] uppercase tracking-wider text-slate-500 font-black">
                  <span className="flex items-center gap-1.5"><FileJson className="w-3 h-3" /> JSON 数据</span>
                  <button onClick={() => handleCopy(formatJSON(previewEntry))} className="text-blue-400 hover:text-blue-300">复制</button>
                </div>
                <div className="bg-black/60 p-4 rounded-2xl font-mono text-[10px] text-slate-400 border border-white/5 max-h-48 overflow-y-auto shadow-inner">
                  <pre className="whitespace-pre-wrap">
                    {formatJSON(previewEntry).split('\n').map((line, i) => {
                      const match = line.match(/"(\w+)":/);
                      if (match) {
                        return (
                          <span key={i}>
                            <span className="text-blue-400/90">"{match[1]}"</span>:
                            <span className="text-orange-400/90">{line.split(match[0])[1]}</span>
                            {'\n'}
                          </span>
                        );
                      }
                      return line + '\n';
                    })}
                  </pre>
                </div>
              </div>

              <button 
                onClick={() => handleCopy(previewEntry.fullPrompt)}
                className="w-full py-4 bg-yellow-400 hover:bg-yellow-500 text-slate-950 rounded-[1.25rem] font-black transition-all flex items-center justify-center gap-2 shadow-xl shadow-yellow-400/20 active:scale-95 text-sm uppercase tracking-widest"
              >
                <Copy className="w-4 h-4" /> 复制反推指令
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Print Only Section */}
      <div className="print-only">
        <div className="flex items-center gap-4 mb-8">
          <div className="w-10 h-10 bg-yellow-400 rounded-lg flex items-center justify-center text-xl">🍌</div>
          <h1 className="text-2xl font-bold">Nano Banana 灵感库导出</h1>
        </div>
        <div className="grid grid-cols-1 gap-6">
          {filteredEntries.map((entry, idx) => (
            <div key={entry.id} className="p-6 border border-gray-200 rounded-2xl break-inside-avoid">
              <div className="flex gap-6">
                <img src={entry.thumbnail} className="w-40 h-40 object-cover rounded-xl" />
                <div className="space-y-3 flex-1">
                  <div className="flex items-center justify-between">
                    <h3 className="text-xl font-bold">#{idx + 1} {entry.summary}</h3>
                    <span className="text-xs font-bold border border-black px-2 py-0.5 rounded uppercase">{entry.category}</span>
                  </div>
                  <div className="grid grid-cols-2 gap-4 text-xs">
                    <p><strong>技术配置:</strong> {entry.cameraInfo}</p>
                    <p><strong>材质描述:</strong> {entry.materialDescription}</p>
                  </div>
                  <p className="text-xs text-gray-500"><strong>关键词:</strong> {entry.tags.join(' • ')}</p>
                  <div className="bg-gray-50 p-4 rounded-lg">
                    <p className="text-sm leading-relaxed italic">"{entry.fullPrompt}"</p>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { PromptEntry, ProcessingState, Category } from './types';
import { analyzeImage, compressImage } from './geminiService';
import { Search, Upload, Copy, Trash2, Printer, Loader2, Filter, X, Check, Edit2, Camera, Layers, Maximize2, FileJson, ChevronRight } from 'lucide-react';

const CATEGORIES: Category[] = ['人物', '风景', '产品', '家居', '动漫', '建筑', '其他'];

const App: React.FC = () => {
  const [entries, setEntries] = useState<PromptEntry[]>([]);
  const [proc, setProc] = useState<ProcessingState>({ total: 0, current: 0, isProcessing: false });
  const [search, setSearch] = useState('');
  const [catFilter, setCatFilter] = useState<Category | '全部'>('全部');
  const [isDragging, setIsDragging] = useState(false);

  const [previewEntry, setPreviewEntry] = useState<PromptEntry | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [tempPrompt, setTempPrompt] = useState('');

  useEffect(() => {
    const saved = localStorage.getItem('nano_banana_db');
    if (saved) setEntries(JSON.parse(saved));
  }, []);

  useEffect(() => {
    localStorage.setItem('nano_banana_db', JSON.stringify(entries));
  }, [entries]);

  const processFiles = async (files: FileList) => {
    if (proc.isProcessing) return;
    const fileArray = Array.from(files).slice(0, 20);
    setProc({ total: fileArray.length, current: 0, isProcessing: true });

    for (let i = 0; i < fileArray.length; i++) {
      try {
        setProc(prev => ({ ...prev, current: i + 1 }));
        const thumb = await compressImage(fileArray[i]);

        const reader = new FileReader();
        const base64: string = await new Promise((resolve) => {
          reader.onload = (e) => resolve(e.target?.result as string);
          reader.readAsDataURL(fileArray[i]);
        });

        const result = await analyzeImage(base64);

        const newEntry: PromptEntry = {
          id: Date.now().toString() + Math.random().toString(36).substr(2, 9),
          thumbnail: thumb,
          ...result,
          createdAt: Date.now()
        };

        setEntries(prev => [newEntry, ...prev]);
      } catch (error) {
        console.error('Failed to process image:', error);
      }
    }
    setProc({ total: 0, current: 0, isProcessing: false });
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    // Simple toast alternative
    const btn = document.activeElement as HTMLElement;
    const originalText = btn.title;
    btn.title = "已复制！";
    setTimeout(() => btn.title = originalText, 2000);
    alert('已成功复制到剪贴板');
  };

  const handleDelete = (id: string) => {
    if (window.confirm('确定要删除这条灵感记录吗？')) {
      setEntries(prev => prev.filter(e => e.id !== id));
    }
  };

  const startEditing = (entry: PromptEntry) => {
    setEditingId(entry.id);
    setTempPrompt(entry.fullPrompt);
  };

  const saveEdit = (id: string) => {
    setEntries(prev => prev.map(e => e.id === id ? { ...e, fullPrompt: tempPrompt } : e));
    setEditingId(null);
  };

  const filteredEntries = useMemo(() => {
    return entries.filter(e => {
      const matchesSearch = 
        e.summary.toLowerCase().includes(search.toLowerCase()) || 
        e.fullPrompt.toLowerCase().includes(search.toLowerCase()) || 
        (e.cameraInfo?.toLowerCase().includes(search.toLowerCase())) ||
        (e.materialDescription?.toLowerCase().includes(search.toLowerCase())) ||
        e.tags.some(t => t.toLowerCase().includes(search.toLowerCase()));
      const matchesCat = catFilter === '全部' || e.category === catFilter;
      return matchesSearch && matchesCat;
    });
  }, [entries, search, catFilter]);

  // Fix: Explicitly trigger print after ensuring call stack is clear
  const handleExport = () => {
    setTimeout(() => {
      window.print();
    }, 100);
  };

  const getCategoryColor = (cat: Category) => {
    const map: Record<Category, string> = {
      '人物': 'bg-pink-500/10 text-pink-400 border-pink-500/20',
      '风景': 'bg-green-500/10 text-green-400 border-green-500/20',
      '产品': 'bg-blue-500/10 text-blue-400 border-blue-500/20',
      '家居': 'bg-orange-500/10 text-orange-400 border-orange-500/20',
      '动漫': 'bg-purple-500/10 text-purple-400 border-purple-500/20',
      '建筑': 'bg-yellow-500/10 text-yellow-400 border-yellow-500/20',
      '其他': 'bg-slate-500/10 text-slate-400 border-slate-500/20',
    };
    return map[cat];
  };

  const formatJSON = (entry: PromptEntry) => {
    const { id, thumbnail, createdAt, ...rest } = entry;
    return JSON.stringify(rest, null, 2);
  };

  return (
    <div className="max-w-7xl mx-auto p-4 md:p-10 space-y-8 min-h-screen font-sans antialiased">
      {/* Header - Hidden on Print */}
      <header className="print:hidden flex flex-col md:flex-row md:items-center justify-between gap-6 bg-slate-900/40 backdrop-blur-2xl p-6 rounded-3xl border border-white/5 shadow-2xl">
        <div className="flex items-center gap-4">
          <div className="w-14 h-14 bg-gradient-to-tr from-yellow-400 to-orange-500 rounded-2xl flex items-center justify-center shadow-lg shadow-orange-500/20 rotate-3">
            <span className="text-3xl">🍌</span>
          </div>
          <div>
            <h1 className="text-2xl font-black tracking-tight bg-gradient-to-r from-white to-slate-400 bg-clip-text text-transparent">NANO BANANA</h1>
            <p className="text-slate-500 text-xs font-bold uppercase tracking-[0.2em]">Prompt Library / 批量反推库</p>
          </div>
        </div>

        {proc.isProcessing && (
          <div className="flex items-center gap-4 bg-black/40 px-5 py-3 rounded-2xl border border-yellow-400/20 shadow-inner">
            <Loader2 className="w-5 h-5 text-yellow-400 animate-spin" />
            <div className="flex flex-col">
              <span className="text-[10px] font-black text-yellow-400/80 uppercase tracking-widest">Processing {proc.current}/{proc.total}</span>
              <div className="w-40 h-1 bg-slate-800 rounded-full mt-1.5 overflow-hidden">
                <div 
                  className="h-full bg-gradient-to-r from-yellow-400 to-orange-500 transition-all duration-500 ease-out shadow-[0_0_8px_rgba(250,204,21,0.5)]" 
                  style={{ width: `${(proc.current / proc.total) * 100}%` }}
                />
              </div>
            </div>
          </div>
        )}
      </header>

      {/* Upload Zone - Hidden on Print */}
      <section 
        className={`print:hidden relative group transition-all duration-500 ease-in-out ${isDragging ? 'scale-[1.02] rotate-1' : ''}`}
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={(e) => { e.preventDefault(); setIsDragging(false); processFiles(e.dataTransfer.files); }}
      >
        <label className={`flex flex-col items-center justify-center w-full h-52 border-2 border-dashed rounded-[2.5rem] cursor-pointer transition-all ${isDragging ? 'border-yellow-400 bg-yellow-400/5 shadow-[0_0_30px_rgba(250,204,21,0.1)]' : 'border-white/10 bg-white/5 hover:border-white/20 hover:bg-white/[0.07]'}`}>
          <div className="flex flex-col items-center justify-center text-center px-6">
            <div className="p-4 bg-white/5 rounded-2xl mb-4 group-hover:scale-110 group-hover:bg-yellow-400/10 group-hover:text-yellow-400 transition-all duration-300">
              <Upload className="w-8 h-8 text-slate-400 transition-colors" />
            </div>
            <p className="mb-2 text-base text-slate-200"><span className="font-black text-yellow-400">点击上传图片</span> 或将文件拖拽至此处</p>
            <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">支持批量反推 (MAX 20 PICS) • GEMINI 3 FLASH 驱动</p>
          </div>
          <input type="file" className="hidden" multiple accept="image/*" onChange={(e) => e.target.files && processFiles(e.target.files)} disabled={proc.isProcessing} />
        </label>
      </section>

      {/* Library Filter - Hidden on Print */}
      <section className="print:hidden space-y-6">
        <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
          <div className="relative flex-1 max-w-xl">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-500" />
            <input 
              type="text" 
              placeholder="搜索简述、技术参数、材质或标签..." 
              className="w-full pl-12 pr-6 py-4 bg-slate-900/50 border border-white/5 rounded-2xl focus:outline-none focus:ring-2 focus:ring-yellow-400/30 text-sm text-slate-100 placeholder:text-slate-600 transition-all shadow-inner"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
          </div>

          <button 
            onClick={handleExport}
            className="flex items-center justify-center gap-2 px-8 py-4 bg-white/5 hover:bg-yellow-400 hover:text-slate-950 border border-white/10 rounded-2xl text-sm font-bold transition-all group active:scale-95"
          >
            <Printer className="w-5 h-5 group-hover:scale-110 transition-transform" /> 导出灵感库 (PDF)
          </button>
        </div>

        {/* Category Filter - Fixed Layout */}
        <div className="flex flex-wrap items-center gap-3 p-1">
          <div className="flex items-center gap-2 pr-4 border-r border-white/10 mr-2">
            <Filter className="w-4 h-4 text-slate-500" />
            <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">筛选</span>
          </div>
          <div className="flex flex-wrap gap-2">
            <button
              onClick={() => setCatFilter('全部')}
              className={`px-5 py-2.5 rounded-xl text-xs font-bold transition-all border ${
                catFilter === '全部' 
                ? 'bg-yellow-400 text-slate-950 border-yellow-400 shadow-lg shadow-yellow-400/20' 
                : 'bg-white/5 text-slate-400 border-white/5 hover:border-white/20 hover:text-slate-200'
              }`}
            >
              全部灵感
            </button>
            {CATEGORIES.map(c => (
              <button
                key={c}
                onClick={() => setCatFilter(c)}
                className={`px-5 py-2.5 rounded-xl text-xs font-bold transition-all border ${
                  catFilter === c 
                  ? 'bg-yellow-400 text-slate-950 border-yellow-400 shadow-lg shadow-yellow-400/20' 
                  : 'bg-white/5 text-slate-400 border-white/5 hover:border-white/20 hover:text-slate-200'
                }`}
              >
                {c}
              </button>
            ))}
          </div>
        </div>
      </section>

      {/* Main Table - Hidden on Print */}
      <main className="print:hidden bg-slate-900/40 backdrop-blur-xl border border-white/5 rounded-[2rem] overflow-hidden shadow-2xl">
        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left border-collapse min-w-[1000px]">
            <thead>
              <tr className="bg-white/[0.02] text-slate-500 text-[10px] font-black uppercase tracking-[0.2em] border-b border-white/5">
                <th className="px-8 py-6">#</th>
                <th className="px-6 py-6">预览</th>
                <th className="px-6 py-6">类别</th>
                <th className="px-6 py-6">画面概括</th>
                <th className="px-6 py-6">技术细节 / 材质</th>
                <th className="px-6 py-6">反推指令 (Prompt)</th>
                <th className="px-8 py-6 text-center">操作</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-white/[0.03]">
              {filteredEntries.map((entry, idx) => (
                <tr key={entry.id} className="group hover:bg-white/[0.02] transition-colors">
                  <td className="px-8 py-6 text-xs text-slate-600 font-mono">{(idx + 1).toString().padStart(2, '0')}</td>
                  <td className="px-6 py-6">
                    <button 
                      className="relative group/img overflow-hidden rounded-2xl border border-white/10 shadow-lg aspect-square w-16"
                      onClick={() => setPreviewEntry(entry)}
                    >
                      <img 
                        src={entry.thumbnail} 
                        alt="thumb" 
                        className="w-full h-full object-cover transition-transform duration-700 group-hover/img:scale-125" 
                      />
                      <div className="absolute inset-0 bg-yellow-400/20 flex items-center justify-center opacity-0 group-hover/img:opacity-100 transition-opacity">
                        <Maximize2 className="w-5 h-5 text-white" />
                      </div>
                    </button>
                  </td>
                  <td className="px-6 py-6">
                    <span className={`px-3 py-1 rounded-lg text-[9px] font-black border uppercase ${getCategoryColor(entry.category)}`}>
                      {entry.category}
                    </span>
                  </td>
                  <td className="px-6 py-6">
                    <p className="text-sm font-bold text-slate-200 w-40 truncate leading-relaxed" title={entry.summary}>{entry.summary}</p>
                    <div className="flex gap-1 mt-1.5 overflow-hidden">
                      {entry.tags.slice(0, 2).map(t => <span key={t} className="text-[9px] text-slate-500 font-medium">#{t}</span>)}
                    </div>
                  </td>
                  <td className="px-6 py-6">
                    <div className="flex flex-col gap-2 max-w-[200px]">
                      <div className="flex items-center gap-2 text-[10px] text-yellow-400/70 bg-yellow-400/5 px-2 py-1 rounded-md border border-yellow-400/10">
                        <Camera className="w-3.5 h-3.5 shrink-0" />
                        <span className="truncate" title={entry.cameraInfo}>{entry.cameraInfo || 'Auto'}</span>
                      </div>
                      <div className="flex items-center gap-2 text-[10px] text-blue-400/70 bg-blue-400/5 px-2 py-1 rounded-md border border-blue-400/10">
                        <Layers className="w-3.5 h-3.5 shrink-0" />
                        <span className="truncate" title={entry.materialDescription}>{entry.materialDescription || 'Standard'}</span>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-6 relative group min-w-[240px]">
                    {editingId === entry.id ? (
                      <div className="flex flex-col gap-2 z-50">
                        <textarea
                          className="w-full bg-slate-950 text-xs text-slate-300 p-4 rounded-xl border border-yellow-400/50 focus:outline-none focus:ring-2 focus:ring-yellow-400/20 min-h-[120px] resize-y shadow-2xl"
                          value={tempPrompt}
                          onChange={(e) => setTempPrompt(e.target.value)}
                          autoFocus
                        />
                        <div className="flex justify-end gap-2">
                          <button onClick={() => setEditingId(null)} className="p-2 bg-white/5 hover:bg-white/10 rounded-lg transition-colors"><X className="w-4 h-4 text-slate-400" /></button>
                          <button onClick={() => saveEdit(entry.id)} className="p-2 bg-yellow-400 text-slate-950 rounded-lg hover:bg-yellow-500"><Check className="w-4 h-4" /></button>
                        </div>
                      </div>
                    ) : (
                      <div 
                        onClick={() => startEditing(entry)}
                        className="text-xs text-slate-400 max-w-xs truncate cursor-text hover:text-yellow-400 group-hover:whitespace-normal group-hover:bg-slate-950 group-hover:p-5 group-hover:absolute group-hover:z-[60] group-hover:shadow-[0_20px_50px_rgba(0,0,0,0.5)] group-hover:rounded-2xl group-hover:border group-hover:border-white/10 group-hover:-top-4 group-hover:-left-4 group-hover:w-80 transition-all flex items-center gap-2 leading-relaxed italic"
                      >
                        "{entry.fullPrompt}"
                        <Edit2 className="w-3 h-3 opacity-0 group-hover:opacity-100 shrink-0 ml-auto" />
                      </div>
                    )}
                  </td>
                  <td className="px-8 py-6">
                    <div className="flex items-center justify-center gap-1">
                      <button onClick={() => handleCopy(entry.fullPrompt)} className="p-3 hover:bg-white/10 rounded-xl text-slate-500 hover:text-yellow-400 transition-all" title="复制提示词"><Copy className="w-4 h-4" /></button>
                      <button onClick={() => handleCopy(formatJSON(entry))} className="p-3 hover:bg-white/10 rounded-xl text-slate-500 hover:text-blue-400 transition-all" title="复制 JSON"><FileJson className="w-4 h-4" /></button>
                      <button onClick={() => handleDelete(entry.id)} className="p-3 hover:bg-red-500/10 rounded-xl text-slate-500 hover:text-red-400 transition-all" title="删除"><Trash2 className="w-4 h-4" /></button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {filteredEntries.length === 0 && (
            <div className="flex flex-col items-center justify-center py-32 text-slate-600">
              <div className="p-8 bg-white/5 rounded-full mb-6 border border-white/5 shadow-inner">
