                      <button onClick={() => handleCopy(formatJSON(entry), '已复制 JSON 数据')} className="p-3 hover:bg-white/10 rounded-xl text-slate-500 hover:text-blue-400 transition-all" title="复制 JSON"><FileJson className="w-4 h-4" /></button>
