                      <div className="absolute inset-0 bg-yellow-400/20 flex items-center justify-center opacity-0 group-hover/img:opacity-100 transition-opacity">
                        <Maximize2 className="w-5 h-5 text-white" />
                      </div>
                    </button>
                  </td>
                  <td className="px-6 py-6">
